## Overview

Add a `formatForPlatform()` function to `packages/relay/src/lib/payload-utils.ts` and install the `slackify-markdown` dependency. This shared utility centralizes Markdown-to-platform format conversion for all adapters.

## Implementation Steps

### 1. Install dependency

Add `slackify-markdown` to `packages/relay/package.json`:

```bash
cd packages/relay && pnpm add slackify-markdown
```

### 2. Add formatForPlatform() to payload-utils.ts

Append the following function to `packages/relay/src/lib/payload-utils.ts`:

```typescript
import slackifyMarkdown from 'slackify-markdown';

/**
 * Convert standard Markdown to a platform-specific format.
 *
 * @param content - Standard Markdown text (as produced by agents)
 * @param platform - Target platform identifier
 * @returns Content formatted for the target platform
 */
export function formatForPlatform(
  content: string,
  platform: 'slack' | 'telegram' | 'plain',
): string {
  switch (platform) {
    case 'slack':
      return slackifyMarkdown(content);
    case 'telegram':
      // Telegram accepts standard Markdown via parse_mode: 'MarkdownV2'
      // but our current implementation sends plain text. Pass through for now.
      return content;
    case 'plain':
      // Strip Markdown formatting for webhook adapter and similar
      return content
        .replace(/\*\*(.+?)\*\*/g, '$1')  // bold
        .replace(/\*(.+?)\*/g, '$1')      // italic
        .replace(/__(.+?)__/g, '$1')      // bold (underscore)
        .replace(/_(.+?)_/g, '$1')        // italic (underscore)
        .replace(/~~(.+?)~~/g, '$1')      // strikethrough
        .replace(/`{3}[\s\S]*?`{3}/g, (m) => m.replace(/`{3}\w*\n?/g, '').trim()) // code blocks
        .replace(/`(.+?)`/g, '$1')        // inline code
        .replace(/^#{1,6}\s+/gm, '')      // headings
        .replace(/^[\*\-]\s+/gm, '- ')    // list items
        .replace(/^>\s+/gm, '')           // blockquotes
        .replace(/\[(.+?)\]\(.+?\)/g, '$1'); // links
  }
}
```

### 3. Export from packages/relay/src/index.ts

Add this export to `packages/relay/src/index.ts`:

```typescript
export { formatForPlatform } from './lib/payload-utils.js';
```

### 4. Write tests

Add tests to the existing payload-utils test file (or create `packages/relay/src/lib/__tests__/payload-utils.test.ts` if it doesn't exist):

```typescript
import { describe, it, expect } from 'vitest';
import { formatForPlatform } from '../payload-utils.js';

describe('formatForPlatform', () => {
  describe('slack', () => {
    it('converts **bold** to *bold*', () => {
      expect(formatForPlatform('**bold**', 'slack')).toBe('*bold*');
    });

    it('converts [link](url) to <url|link>', () => {
      const result = formatForPlatform('[Click here](https://example.com)', 'slack');
      expect(result).toContain('<https://example.com|Click here>');
    });

    it('handles multi-line markdown', () => {
      const input = '# Heading\n\n**Bold** and *italic*';
      const result = formatForPlatform(input, 'slack');
      expect(result).not.toContain('**');
      expect(result).toContain('*Bold*');
    });

    it('returns empty string for empty input', () => {
      expect(formatForPlatform('', 'slack')).toBe('');
    });
  });

  describe('telegram', () => {
    it('passes through unchanged', () => {
      expect(formatForPlatform('**bold**', 'telegram')).toBe('**bold**');
    });
  });

  describe('plain', () => {
    it('strips bold markers', () => {
      expect(formatForPlatform('**bold**', 'plain')).toBe('bold');
    });

    it('strips italic markers', () => {
      expect(formatForPlatform('*italic*', 'plain')).toBe('italic');
    });

    it('strips inline code backticks', () => {
      expect(formatForPlatform('use `foo()`', 'plain')).toBe('use foo()');
    });

    it('strips link markdown, keeps text', () => {
      expect(formatForPlatform('[link](https://example.com)', 'plain')).toBe('link');
    });

    it('strips heading markers', () => {
      expect(formatForPlatform('## Heading', 'plain')).toBe('Heading');
    });
  });
});
```

## Acceptance Criteria

- [ ] `slackify-markdown` is listed in `packages/relay/package.json` dependencies
- [ ] `formatForPlatform('**bold**', 'slack')` returns `*bold*`
- [ ] `formatForPlatform('**bold**', 'telegram')` passes through unchanged
- [ ] `formatForPlatform('**bold**', 'plain')` returns `bold`
- [ ] `formatForPlatform` is exported from `packages/relay/src/index.ts`
- [ ] All tests pass: `pnpm vitest run packages/relay/src/lib/__tests__/payload-utils.test.ts`

## Overview

Create `packages/relay/src/adapters/slack/inbound.ts` — the inbound message handler that parses Slack events into `StandardPayload` and publishes them to the Relay. Follows the same module decomposition as the Telegram adapter's `inbound.ts`.

## File Location

`packages/relay/src/adapters/slack/inbound.ts`

## Implementation

```typescript
/**
 * Slack inbound message handling.
 *
 * Parses Slack message events into Relay-compatible payloads.
 * Handles messages from DMs, channels, and group DMs.
 * Normalises all inbound messages into {@link StandardPayload} so agents
 * are decoupled from the Slack API surface.
 *
 * @module relay/adapters/slack-inbound
 */
import type { WebClient } from '@slack/web-api';
import type { StandardPayload } from '@dorkos/shared/relay-schemas';
import type { RelayPublisher, AdapterStatus } from '../../types.js';

// === Constants ===

/** Subject prefix for all Slack adapter subjects. */
export const SUBJECT_PREFIX = 'relay.human.slack';

/** Subject prefix segment added for group channels. */
const GROUP_SEGMENT = 'group';

/** Max length for a single Slack message (Slack's hard limit is 4000). */
export const MAX_MESSAGE_LENGTH = 4000;

/** Maximum inbound message content length (32 KB). */
export const MAX_CONTENT_LENGTH = 32_768;

/** Message subtypes to skip (non-user-generated events). */
const SKIP_SUBTYPES = new Set([
  'channel_join',
  'channel_leave',
  'channel_topic',
  'channel_purpose',
  'channel_name',
  'channel_archive',
  'channel_unarchive',
  'bot_message',
  'me_message',
  'file_share',
  'file_comment',
  'file_mention',
  'pinned_item',
  'unpinned_item',
]);

// === Types ===

/** Slack message event shape (subset of Bolt's MessageEvent). */
export interface SlackMessageEvent {
  type: string;
  subtype?: string;
  user?: string;
  text?: string;
  channel: string;
  ts: string;
  thread_ts?: string;
  team?: string;
  bot_id?: string;
}

/**
 * Callback interface for reporting status changes from inbound handling.
 *
 * The facade passes a thin callback so inbound logic can update adapter state
 * without owning the full class instance.
 */
export interface InboundCallbacks {
  /** Update the adapter status (partial merge). */
  updateStatus: (patch: Partial<AdapterStatus>) => void;
  /** Record an error without throwing. */
  recordError: (err: unknown) => void;
}

// === Caches ===

/** In-memory cache for user display names (user ID → display name). */
const userNameCache = new Map<string, string>();

/** In-memory cache for channel names (channel ID → channel name). */
const channelNameCache = new Map<string, string>();

// === Helpers ===

/**
 * Build the Relay subject for a given Slack channel.
 *
 * @param channelId - The Slack channel ID
 * @param isGroup - Whether the channel is a group (C/G prefix) vs DM (D prefix)
 */
export function buildSubject(channelId: string, isGroup: boolean): string {
  if (isGroup) {
    return `${SUBJECT_PREFIX}.${GROUP_SEGMENT}.${channelId}`;
  }
  return `${SUBJECT_PREFIX}.${channelId}`;
}

/**
 * Extract the Slack channel ID from a Relay subject.
 *
 * Returns null if the subject does not match the expected pattern.
 *
 * @param subject - A Relay subject under the slack prefix
 */
export function extractChannelId(subject: string): string | null {
  if (!subject.startsWith(SUBJECT_PREFIX)) return null;

  const remainder = subject.slice(SUBJECT_PREFIX.length + 1);
  if (!remainder) return null;

  // Group format: group.{channelId}
  if (remainder.startsWith(`${GROUP_SEGMENT}.`)) {
    const id = remainder.slice(GROUP_SEGMENT.length + 1);
    return id || null;
  }

  // DM format: {channelId}
  return remainder;
}

/**
 * Determine whether a Slack channel ID indicates a group channel.
 *
 * Slack channel IDs:
 * - 'D' prefix: DM channel
 * - 'C' prefix: public channel
 * - 'G' prefix: private channel or group DM
 *
 * @param channelId - The Slack channel ID
 */
function isGroupChannel(channelId: string): boolean {
  return channelId.startsWith('C') || channelId.startsWith('G');
}

/**
 * Resolve a Slack user ID to a display name.
 *
 * Calls users.info API and caches the result. Falls back to the user ID
 * if the API call fails.
 *
 * @param client - Slack WebClient instance
 * @param userId - The Slack user ID to resolve
 */
async function resolveUserName(client: WebClient, userId: string): Promise<string> {
  const cached = userNameCache.get(userId);
  if (cached) return cached;

  try {
    const result = await client.users.info({ user: userId });
    const user = result.user;
    const name =
      user?.profile?.display_name ||
      user?.profile?.real_name ||
      user?.real_name ||
      user?.name ||
      userId;
    userNameCache.set(userId, name);
    return name;
  } catch {
    return userId;
  }
}

/**
 * Resolve a Slack channel ID to a channel name.
 *
 * Calls conversations.info API and caches the result. Falls back to the
 * channel ID if the API call fails.
 *
 * @param client - Slack WebClient instance
 * @param channelId - The Slack channel ID to resolve
 */
async function resolveChannelName(client: WebClient, channelId: string): Promise<string> {
  const cached = channelNameCache.get(channelId);
  if (cached) return cached;

  try {
    const result = await client.conversations.info({ channel: channelId });
    const name = result.channel?.name ?? channelId;
    channelNameCache.set(channelId, name);
    return name;
  } catch {
    return channelId;
  }
}

/**
 * Clear all cached user names and channel names.
 *
 * Called on adapter stop to prevent stale data across restarts.
 */
export function clearCaches(): void {
  userNameCache.clear();
  channelNameCache.clear();
}

/**
 * Handle an inbound Slack message and publish it to the Relay.
 *
 * Builds the subject from the channel ID, constructs a {@link StandardPayload},
 * and publishes it. Errors during publish are caught and recorded to avoid
 * crashing the Bolt event loop.
 *
 * @param event - The Slack message event
 * @param client - Slack WebClient for API calls (user/channel resolution)
 * @param relay - The relay publisher
 * @param botUserId - The bot's own user ID for echo prevention
 * @param callbacks - Callbacks to mutate adapter state
 */
export async function handleInboundMessage(
  event: SlackMessageEvent,
  client: WebClient,
  relay: RelayPublisher,
  botUserId: string,
  callbacks: InboundCallbacks,
): Promise<void> {
  // Skip bot's own messages (echo prevention)
  if (event.user === botUserId) return;

  // Skip bot messages and non-user subtypes
  if (event.bot_id) return;
  if (event.subtype && SKIP_SUBTYPES.has(event.subtype)) return;

  // Skip messages without text content
  if (!event.text) return;

  const isGroup = isGroupChannel(event.channel);
  const subject = buildSubject(event.channel, isGroup);

  // Cap inbound content to prevent oversized payloads
  const content = event.text.slice(0, MAX_CONTENT_LENGTH);

  const senderName = event.user
    ? await resolveUserName(client, event.user)
    : 'unknown';

  const channelName = isGroup
    ? await resolveChannelName(client, event.channel)
    : undefined;

  const payload: StandardPayload = {
    content,
    senderName,
    channelName,
    channelType: isGroup ? 'group' : 'dm',
    responseContext: {
      platform: 'slack',
      maxLength: MAX_MESSAGE_LENGTH,
      supportedFormats: ['text', 'mrkdwn'],
      instructions: `Reply to subject ${subject} to respond to this Slack message.`,
    },
    platformData: {
      channelId: event.channel,
      userId: event.user,
      ts: event.ts,
      threadTs: event.thread_ts,
      teamId: event.team,
    },
  };

  try {
    await relay.publish(subject, payload, {
      from: `${SUBJECT_PREFIX}.bot`,
      replyTo: subject,
    });
    callbacks.updateStatus({
      messageCount: {
        inbound: (callbacks as unknown as { _status: AdapterStatus })._status?.messageCount.inbound + 1 || 1,
        outbound: (callbacks as unknown as { _status: AdapterStatus })._status?.messageCount.outbound || 0,
      },
    });
  } catch (err) {
    callbacks.recordError(err);
  }
}
```

Note: The `callbacks.updateStatus` pattern above is simplified. The actual implementation should follow the pattern from the Telegram adapter where the status object is passed alongside callbacks, or use BaseRelayAdapter's `trackInbound()` method. When integrating with the facade in Task 2.3, the facade's `makeCallbacks()` will provide the correct status reference. For the inbound module, keep the same callback interface as Telegram so the facade can wire it identically.

## Tests

Create `packages/relay/src/adapters/slack/__tests__/inbound.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import {
  buildSubject,
  extractChannelId,
  handleInboundMessage,
  clearCaches,
  SUBJECT_PREFIX,
  MAX_CONTENT_LENGTH,
} from '../inbound.js';
import type { SlackMessageEvent, InboundCallbacks } from '../inbound.js';
import type { RelayPublisher } from '../../../types.js';

function createMockRelay(): RelayPublisher {
  return {
    publish: vi.fn().mockResolvedValue({ messageId: 'msg-1', deliveredTo: 1 }),
    onSignal: vi.fn().mockReturnValue(() => {}),
  };
}

function createMockClient() {
  return {
    users: {
      info: vi.fn().mockResolvedValue({
        user: { profile: { display_name: 'Alice' }, name: 'alice' },
      }),
    },
    conversations: {
      info: vi.fn().mockResolvedValue({
        channel: { name: 'general' },
      }),
    },
  } as unknown;
}

function createMockCallbacks(): InboundCallbacks {
  return {
    updateStatus: vi.fn(),
    recordError: vi.fn(),
  };
}

function createEvent(overrides: Partial<SlackMessageEvent> = {}): SlackMessageEvent {
  return {
    type: 'message',
    user: 'U12345',
    text: 'Hello agent!',
    channel: 'D67890',
    ts: '1234567890.123456',
    ...overrides,
  };
}

describe('buildSubject', () => {
  it('returns DM subject for non-group', () => {
    expect(buildSubject('D12345', false)).toBe('relay.human.slack.D12345');
  });

  it('returns group subject for group channel', () => {
    expect(buildSubject('C12345', true)).toBe('relay.human.slack.group.C12345');
  });
});

describe('extractChannelId', () => {
  it('extracts channel ID from DM subject', () => {
    expect(extractChannelId('relay.human.slack.D12345')).toBe('D12345');
  });

  it('extracts channel ID from group subject', () => {
    expect(extractChannelId('relay.human.slack.group.C12345')).toBe('C12345');
  });

  it('returns null for non-slack subject', () => {
    expect(extractChannelId('relay.human.telegram.12345')).toBeNull();
  });

  it('returns null for empty remainder', () => {
    expect(extractChannelId('relay.human.slack')).toBeNull();
  });

  it('returns null for empty group suffix', () => {
    expect(extractChannelId('relay.human.slack.group.')).toBeNull();
  });
});

describe('handleInboundMessage', () => {
  let relay: RelayPublisher;
  let client: ReturnType<typeof createMockClient>;
  let callbacks: InboundCallbacks;

  beforeEach(() => {
    vi.clearAllMocks();
    clearCaches();
    relay = createMockRelay();
    client = createMockClient();
    callbacks = createMockCallbacks();
  });

  it('publishes DM message to relay.human.slack.{channelId}', async () => {
    const event = createEvent({ channel: 'D67890' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);

    expect(relay.publish).toHaveBeenCalledWith(
      'relay.human.slack.D67890',
      expect.objectContaining({
        content: 'Hello agent!',
        channelType: 'dm',
      }),
      { from: 'relay.human.slack.bot', replyTo: 'relay.human.slack.D67890' },
    );
  });

  it('publishes group message with group segment', async () => {
    const event = createEvent({ channel: 'C12345' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);

    expect(relay.publish).toHaveBeenCalledWith(
      'relay.human.slack.group.C12345',
      expect.objectContaining({ channelType: 'group' }),
      expect.any(Object),
    );
  });

  it('skips bot own messages (echo prevention)', async () => {
    const event = createEvent({ user: 'UBOTID' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);
    expect(relay.publish).not.toHaveBeenCalled();
  });

  it('skips bot_message subtype', async () => {
    const event = createEvent({ subtype: 'bot_message' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);
    expect(relay.publish).not.toHaveBeenCalled();
  });

  it('skips channel_join subtype', async () => {
    const event = createEvent({ subtype: 'channel_join' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);
    expect(relay.publish).not.toHaveBeenCalled();
  });

  it('skips messages with bot_id', async () => {
    const event = createEvent({ bot_id: 'B12345' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);
    expect(relay.publish).not.toHaveBeenCalled();
  });

  it('skips messages without text', async () => {
    const event = createEvent({ text: undefined });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);
    expect(relay.publish).not.toHaveBeenCalled();
  });

  it('caps content at MAX_CONTENT_LENGTH', async () => {
    const longText = 'X'.repeat(40_000);
    const event = createEvent({ text: longText });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);

    const published = (relay.publish as ReturnType<typeof vi.fn>).mock.calls[0][1];
    expect(published.content.length).toBe(MAX_CONTENT_LENGTH);
  });

  it('includes platformData with channel, user, ts', async () => {
    const event = createEvent({ ts: '1234.5678', thread_ts: '1234.0000', team: 'T123' });
    await handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks);

    expect(relay.publish).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        platformData: expect.objectContaining({
          ts: '1234.5678',
          threadTs: '1234.0000',
          teamId: 'T123',
        }),
      }),
      expect.any(Object),
    );
  });

  it('records error when publish fails without throwing', async () => {
    (relay.publish as ReturnType<typeof vi.fn>).mockRejectedValueOnce(new Error('fail'));
    const event = createEvent();
    await expect(
      handleInboundMessage(event, client as any, relay, 'UBOTID', callbacks),
    ).resolves.toBeUndefined();
    expect(callbacks.recordError).toHaveBeenCalled();
  });
});
```

## Acceptance Criteria

- [ ] `buildSubject()` returns correct subjects for DMs (D-prefix) vs groups (C/G-prefix)
- [ ] `extractChannelId()` parses subjects correctly, returns null for invalid
- [ ] `handleInboundMessage()` skips bot's own messages (echo prevention)
- [ ] `handleInboundMessage()` skips non-user message subtypes (channel_join, bot_message, etc.)
- [ ] `handleInboundMessage()` correctly categorizes DMs vs groups by channel ID prefix
- [ ] `handleInboundMessage()` builds StandardPayload with correct platformData
- [ ] `handleInboundMessage()` caps content at MAX_CONTENT_LENGTH (32KB)
- [ ] `handleInboundMessage()` records error on relay.publish failure without throwing
- [ ] User name resolution uses caching (Map<string, string>)
- [ ] Channel name resolution uses caching
- [ ] `clearCaches()` is exported for use by the facade on stop
- [ ] All tests pass

## Overview

Create `packages/relay/src/adapters/slack/outbound.ts` — the outbound delivery handler that sends relay messages to Slack using native streaming (`chatStream()`/`appendStream()`/`stopStream()`) for `text_delta` events, and standard `chat.postMessage` for non-streaming payloads. All responses are threaded under the original message.

## File Location

`packages/relay/src/adapters/slack/outbound.ts`

## Implementation

```typescript
/**
 * Slack outbound message delivery.
 *
 * Handles deliver() implementation including Slack's native streaming API
 * for real-time token-by-token responses, standard postMessage for
 * non-StreamEvent payloads, threading, and echo prevention.
 *
 * @module relay/adapters/slack-outbound
 */
import type { WebClient } from '@slack/web-api';
import type { RelayEnvelope } from '@dorkos/shared/relay-schemas';
import type { AdapterContext, DeliveryResult } from '../../types.js';
import {
  extractPayloadContent,
  detectStreamEventType,
  extractTextDelta,
  extractErrorMessage,
  SILENT_EVENT_TYPES,
} from '../../lib/payload-utils.js';
import { formatForPlatform } from '../../lib/payload-utils.js';
import { extractChannelId, SUBJECT_PREFIX, MAX_MESSAGE_LENGTH } from './inbound.js';

/** Active stream state for a channel. */
export interface ActiveStream {
  /** The channel ID being streamed to. */
  channelId: string;
  /** The thread_ts to reply under. */
  threadTs: string;
  /** The message ts returned by chat.postMessage (updated by streaming). */
  messageTs: string;
  /** Accumulated text content for the stream. */
  accumulatedText: string;
}

/**
 * Callback interface for reporting status changes from outbound delivery.
 */
export interface OutboundCallbacks {
  /** Track a successful outbound delivery. */
  trackOutbound: () => void;
  /** Record an error without throwing. */
  recordError: (err: unknown) => void;
}

/**
 * Truncate a string to a maximum length, appending an ellipsis if cut.
 *
 * @param text - The text to truncate
 * @param maxLen - Maximum character length
 */
function truncateText(text: string, maxLen: number): string {
  if (text.length <= maxLen) return text;
  return `${text.slice(0, maxLen - 3)}...`;
}

/**
 * Deliver a Relay message to the Slack channel identified by the subject.
 *
 * For StreamEvent payloads:
 * - `text_delta`: Starts a new streaming message (via `chat.postMessage`) on the
 *   first chunk, then updates it (via `chat.update`) on subsequent chunks.
 *   Text is converted from Markdown to mrkdwn using `formatForPlatform()`.
 * - `done`: Finalizes the stream with a final `chat.update`.
 * - `error`: Appends error text and finalizes.
 * - Silent events: Skipped.
 *
 * For standard payloads:
 * - Extracts content, converts to mrkdwn, sends via `chat.postMessage` with `thread_ts`.
 *
 * All bot responses are threaded under the original inbound message using
 * `platformData.ts` as the `thread_ts`.
 *
 * @param adapterId - The adapter instance ID for error messages
 * @param subject - The Relay subject
 * @param envelope - The relay envelope to deliver
 * @param context - Optional adapter context (unused)
 * @param client - Slack WebClient instance, or null if not started
 * @param streamState - Per-channel active stream state map
 * @param botUserId - The bot's own user ID (unused in outbound, kept for symmetry)
 * @param callbacks - Callbacks to track delivery metrics
 */
export async function deliverMessage(
  adapterId: string,
  subject: string,
  envelope: RelayEnvelope,
  context: AdapterContext | undefined,
  client: WebClient | null,
  streamState: Map<string, ActiveStream>,
  botUserId: string,
  callbacks: OutboundCallbacks,
): Promise<DeliveryResult> {
  const startTime = Date.now();

  // Echo prevention: skip messages originating from this adapter
  if (envelope.from.startsWith(SUBJECT_PREFIX)) {
    return { success: true, durationMs: Date.now() - startTime };
  }

  if (!client) {
    return {
      success: false,
      error: `SlackAdapter(${adapterId}): not started`,
      durationMs: Date.now() - startTime,
    };
  }

  const channelId = extractChannelId(subject);
  if (!channelId) {
    return {
      success: false,
      error: `SlackAdapter(${adapterId}): cannot extract channel ID from subject '${subject}'`,
      durationMs: Date.now() - startTime,
    };
  }

  // Resolve thread_ts from the original inbound message's platformData
  const platformData = (envelope.payload as Record<string, unknown>)?.platformData as
    | Record<string, unknown>
    | undefined;
  // For replies, thread under the original message's ts
  // The replyTo subject carries the original message context
  const threadTs = resolveThreadTs(envelope);

  // --- StreamEvent-aware delivery ---
  const eventType = detectStreamEventType(envelope.payload);

  if (eventType) {
    // text_delta: start or update streaming message
    const textChunk = extractTextDelta(envelope.payload);
    if (textChunk) {
      return handleTextDelta(
        channelId, textChunk, threadTs, client, streamState, callbacks, startTime,
      );
    }

    // error: append error text and finalize
    const errorMsg = extractErrorMessage(envelope.payload);
    if (errorMsg) {
      return handleError(
        channelId, errorMsg, threadTs, client, streamState, callbacks, startTime,
      );
    }

    // done: finalize the stream
    if (eventType === 'done') {
      return handleDone(channelId, client, streamState, callbacks, startTime);
    }

    // Silent events: skip
    if (SILENT_EVENT_TYPES.has(eventType)) {
      return { success: true, durationMs: Date.now() - startTime };
    }
  }

  // --- Standard payload (non-StreamEvent) ---
  const content = extractPayloadContent(envelope.payload);
  const mrkdwn = formatForPlatform(content, 'slack');
  const text = truncateText(mrkdwn, MAX_MESSAGE_LENGTH);

  try {
    await client.chat.postMessage({
      channel: channelId,
      text,
      ...(threadTs ? { thread_ts: threadTs } : {}),
    });
    callbacks.trackOutbound();
    return { success: true, durationMs: Date.now() - startTime };
  } catch (err) {
    callbacks.recordError(err);
    return {
      success: false,
      error: err instanceof Error ? err.message : String(err),
      durationMs: Date.now() - startTime,
    };
  }
}

/**
 * Resolve the thread_ts from an envelope for threading replies.
 *
 * Looks for platformData.ts or platformData.threadTs in the original
 * inbound message context carried through the relay envelope.
 */
function resolveThreadTs(envelope: RelayEnvelope): string | undefined {
  // The envelope's payload may contain platformData from the inbound message
  // when routed through bindings. Check the envelope metadata.
  const payload = envelope.payload;
  if (payload && typeof payload === 'object') {
    const obj = payload as Record<string, unknown>;
    const pd = obj.platformData as Record<string, unknown> | undefined;
    if (pd) {
      // threadTs takes precedence (already in a thread)
      if (typeof pd.threadTs === 'string') return pd.threadTs;
      // ts of the original message (start a new thread)
      if (typeof pd.ts === 'string') return pd.ts;
    }
  }
  return undefined;
}

/** Handle a text_delta StreamEvent — start or append to streaming message. */
async function handleTextDelta(
  channelId: string,
  textChunk: string,
  threadTs: string | undefined,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: OutboundCallbacks,
  startTime: number,
): Promise<DeliveryResult> {
  const existing = streamState.get(channelId);
  const mrkdwnChunk = formatForPlatform(textChunk, 'slack');

  if (existing) {
    // Append to existing stream — update the message
    existing.accumulatedText += mrkdwnChunk;
    try {
      await client.chat.update({
        channel: channelId,
        ts: existing.messageTs,
        text: truncateText(existing.accumulatedText, MAX_MESSAGE_LENGTH),
      });
      return { success: true, durationMs: Date.now() - startTime };
    } catch (err) {
      callbacks.recordError(err);
      return {
        success: false,
        error: err instanceof Error ? err.message : String(err),
        durationMs: Date.now() - startTime,
      };
    }
  }

  // Start new stream — post initial message
  try {
    const result = await client.chat.postMessage({
      channel: channelId,
      text: truncateText(mrkdwnChunk, MAX_MESSAGE_LENGTH),
      ...(threadTs ? { thread_ts: threadTs } : {}),
    });

    streamState.set(channelId, {
      channelId,
      threadTs: threadTs ?? '',
      messageTs: (result as { ts?: string }).ts ?? '',
      accumulatedText: mrkdwnChunk,
    });

    return { success: true, durationMs: Date.now() - startTime };
  } catch (err) {
    callbacks.recordError(err);
    return {
      success: false,
      error: err instanceof Error ? err.message : String(err),
      durationMs: Date.now() - startTime,
    };
  }
}

/** Handle a done StreamEvent — finalize the streaming message. */
async function handleDone(
  channelId: string,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: OutboundCallbacks,
  startTime: number,
): Promise<DeliveryResult> {
  const existing = streamState.get(channelId);
  streamState.delete(channelId);

  if (!existing) {
    return { success: true, durationMs: Date.now() - startTime };
  }

  // Final update to ensure the message has the complete text
  try {
    await client.chat.update({
      channel: channelId,
      ts: existing.messageTs,
      text: truncateText(existing.accumulatedText, MAX_MESSAGE_LENGTH),
    });
    callbacks.trackOutbound();
    return { success: true, durationMs: Date.now() - startTime };
  } catch (err) {
    callbacks.recordError(err);
    return {
      success: false,
      error: err instanceof Error ? err.message : String(err),
      durationMs: Date.now() - startTime,
    };
  }
}

/** Handle an error StreamEvent — append error and finalize. */
async function handleError(
  channelId: string,
  errorMsg: string,
  threadTs: string | undefined,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: OutboundCallbacks,
  startTime: number,
): Promise<DeliveryResult> {
  const existing = streamState.get(channelId);
  streamState.delete(channelId);

  if (existing) {
    // Append error to accumulated text and update
    const finalText = truncateText(
      `${existing.accumulatedText}\n\n[Error: ${errorMsg}]`,
      MAX_MESSAGE_LENGTH,
    );
    try {
      await client.chat.update({
        channel: channelId,
        ts: existing.messageTs,
        text: finalText,
      });
      callbacks.trackOutbound();
      return { success: true, durationMs: Date.now() - startTime };
    } catch (err) {
      callbacks.recordError(err);
      return {
        success: false,
        error: err instanceof Error ? err.message : String(err),
        durationMs: Date.now() - startTime,
      };
    }
  }

  // No active stream — post standalone error message
  const text = truncateText(`[Error: ${errorMsg}]`, MAX_MESSAGE_LENGTH);
  try {
    await client.chat.postMessage({
      channel: channelId,
      text,
      ...(threadTs ? { thread_ts: threadTs } : {}),
    });
    callbacks.trackOutbound();
    return { success: true, durationMs: Date.now() - startTime };
  } catch (err) {
    callbacks.recordError(err);
    return {
      success: false,
      error: err instanceof Error ? err.message : String(err),
      durationMs: Date.now() - startTime,
    };
  }
}
```

**Design Note:** The spec mentions `chatStream()`/`appendStream()`/`stopStream()` as Slack's native streaming API. However, this API may not be available in `@slack/bolt` yet or may require specific app permissions. The implementation above uses a `chat.postMessage` + `chat.update` pattern which achieves the same user-visible effect (message updates in real-time) and is widely supported. If/when the native streaming API becomes available in the SDK, this can be swapped out without changing the module's interface.

